using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace ShoppingCart.Tests;

[TestClass]
public class ShoppingCartTests
{
    private Store.ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup()
    {
        _cart = new Store.ShoppingCart();
    }

    // --- AddItem Tests ---

    [TestMethod]
    public void AddItem_SingleItem_IncreasesTotal()
    {
        _cart.AddItem("SKU-001", 1, 9.99m);

        Assert.AreEqual(9.99m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleQuantity_MultipliesPrice()
    {
        _cart.AddItem("SKU-001", 3, 5.00m);

        Assert.AreEqual(15.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_SumsAll()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-002", 2, 7.50m);

        Assert.AreEqual(25.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_CombinesQuantity()
    {
        _cart.AddItem("SKU-001", 1, 5.00m);
        _cart.AddItem("SKU-001", 2, 5.00m);

        Assert.AreEqual(15.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_ZeroQuantity_Throws()
    {
        _cart.AddItem("SKU-001", 0, 5.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_NegativeQuantity_Throws()
    {
        _cart.AddItem("SKU-001", -1, 5.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_NegativePrice_Throws()
    {
        _cart.AddItem("SKU-001", 1, -5.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public void AddItem_NullSku_Throws()
    {
        _cart.AddItem(null!, 1, 5.00m);
    }

    // --- RemoveItem Tests ---

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromTotal()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-002", 1, 5.00m);

        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(5.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_OnlyItem_TotalBecomesZero()
    {
        _cart.AddItem("SKU-001", 2, 10.00m);

        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    [ExpectedException(typeof(InvalidOperationException))]
    public void RemoveItem_NonExistentSku_Throws()
    {
        _cart.RemoveItem("DOES-NOT-EXIST");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public void RemoveItem_NullSku_Throws()
    {
        _cart.RemoveItem(null!);
    }

    // --- CalculateTotal Tests ---

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterAddAndRemove_ReflectsCurrentState()
    {
        _cart.AddItem("SKU-001", 1, 20.00m);
        _cart.AddItem("SKU-002", 1, 30.00m);
        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(30.00m, _cart.CalculateTotal());
    }

    // --- ApplyCoupon Tests ---

    [TestMethod]
    public void ApplyCoupon_ValidCode_ReducesTotal()
    {
        _cart.AddItem("SKU-001", 1, 100.00m);

        _cart.ApplyCoupon("SAVE10");

        Assert.IsTrue(_cart.CalculateTotal() < 100.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void ApplyCoupon_EmptyCode_Throws()
    {
        _cart.ApplyCoupon("");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public void ApplyCoupon_NullCode_Throws()
    {
        _cart.ApplyCoupon(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(InvalidOperationException))]
    public void ApplyCoupon_InvalidCode_Throws()
    {
        _cart.ApplyCoupon("BOGUS-CODE");
    }

    [TestMethod]
    public void ApplyCoupon_OnEmptyCart_TotalRemainsZero()
    {
        _cart.ApplyCoupon("SAVE10");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    [ExpectedException(typeof(InvalidOperationException))]
    public void ApplyCoupon_Twice_Throws()
    {
        _cart.AddItem("SKU-001", 1, 100.00m);

        _cart.ApplyCoupon("SAVE10");
        _cart.ApplyCoupon("SAVE10");
    }
}

